+    #[command(name = "list")]
+    List,
+
+    /// Clear expired entries and optionally wipe stores
+    #[command(name = "clear")]
+    Clear(AllowOnceClearArgs),
+
+    /// Revoke a pending code or active allow-once entry
+    #[command(name = "revoke")]
+    Revoke(AllowOnceRevokeArgs),
+}
